const e=JSON.parse('{"key":"v-2b3d02d4","path":"/project/PC%E7%AB%AF%E4%B8%8E%E7%A7%BB%E5%8A%A8%E7%AB%AF%E7%9A%84%E9%A1%B5%E9%9D%A2%E5%8D%A1%E9%A1%BF%E7%9A%84%E4%BC%98%E5%8C%96.html","title":"PC端与移动端的页面卡顿的优化","lang":"zh-CN","frontmatter":{"title":"PC端与移动端的页面卡顿的优化","isTimeLine":true,"date":"2026-02-16T00:00:00.000Z","category":["前端"],"tag":["JavaScript","性能优化"]},"headers":[{"level":3,"title":"PC场景","slug":"pc场景","link":"#pc场景","children":[]},{"level":3,"title":"PC解决方案","slug":"pc解决方案","link":"#pc解决方案","children":[]},{"level":3,"title":"PC端实现","slug":"pc端实现","link":"#pc端实现","children":[]},{"level":3,"title":"手机端场景","slug":"手机端场景","link":"#手机端场景","children":[]},{"level":3,"title":"手机端性能优化","slug":"手机端性能优化","link":"#手机端性能优化","children":[]}],"git":{"createdTime":1773506313000,"updatedTime":1773506313000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":4.62,"words":1385},"filePathRelative":"project/PC端与移动端的页面卡顿的优化.md","localizedDate":"2026年2月16日","excerpt":"<h3> PC场景</h3>\\n<ul>\\n<li>随着数据量增多,系统一些复杂页面的加载速度、响应速度越来越慢，用户体验不好</li>\\n</ul>\\n<h3> PC解决方案</h3>\\n<ul>\\n<li>加载阶段，从发出请求到渲染出完整页面的过程，影响到这个阶段的主要因素有网络和JavaScript脚本</li>\\n<li>所以就是降低关键资源大小与个数；交互阶段就是减少DOM个数、DOM操作，避免重排重绘，使用防抖节流</li>\\n</ul>\\n<h3> PC端实现</h3>\\n<ol>\\n<li>文件体积上：延迟加载非关键资源，减少关键资源的个数，优先加载关键CSS和JS\\n<ul>\\n<li>解决：路由懒加载、全局组件改为懒加载、弹窗的数据改为点击后才请求。</li>\\n<li><code>import()</code>函数导入组件，Webpack在打包时会将异步导入拆分成单独的<code>chunk</code>文件。通过<code>webpackChunkName</code>设置分割后代码块的名字</li>\\n</ul>\\n</li>\\n<li>缓存上：利用浏览器的缓存机制\\n<ul>\\n<li>文件资源进行强缓存、协商缓存，在服务器设置了正确的响应头时才会生效</li>\\n<li>其中HTML文档不要缓存，要保持非缓存状态：<code>Cache-Control: no-store；</code>其他文件有变化了才能引入新的文件路径。</li>\\n<li><code>Expires、Cache-control，last-modify、etag</code>这些强缓存、协商缓存相关的<code>Header</code>可以让浏览器高效地利用文件缓存。只有当文件的内容修改了，才会重新加载文件（打包后的静态资源都会带上一串 Hash 值）</li>\\n</ul>\\n</li>\\n<li>indexDB缓存：不怎么修改的数据用<code>indexDB</code>存储，为了减少数据请求的接口。\\n<ul>\\n<li>一些各个流程都用到的资源数据改为了<code>indexDB</code>缓存，比如检测方法、检测项目这些名字、标准号等这些是国家标准，一般新增后不会改动，所以存在本地的indexDB上。</li>\\n<li>修改：数据的关键字段有变动时候，再通知<code>indexDB</code>数据更改。使用了<code>websoket</code>进行消息通知，如果数据有变动就清空<code>indexDB</code>数据列表，下次用到重新请求并存储。</li>\\n<li>使用：封装数量列表在全局变量上，系统各个地方就可以直接使用，无需请求接口。<code>await this.$app.webdata.getdatas(\\"lims.analysisitem\\")</code></li>\\n</ul>\\n</li>\\n<li>渲染上：大数据的场景使用虚拟列表组件\\n<ul>\\n<li>虚拟滚动指的是只渲染可视区域的列表项，非可见区域的不渲染，在滚动时动态更新可视区域；</li>\\n<li>一些数据的弹窗选择组件，就算数据从缓存拿不走接口，但是一下子加载一千多节点，页面还是用户体验不好。</li>\\n<li>系统多出弹窗使用组件库<code>vue-virtual-scroller</code>封装的<code>fx-table</code>，用它替换到之前的组件，达到渲染上优化。</li>\\n<li>基本原理：计算出<code>totalHeight</code>列表总高度，并在触发时滚动事件时根据<code>scrollTop</code>值不断更新<code>startIndex</code>以及<code>endIndex</code>，最后从列表数据<code>listData</code>中截取对应元素。</li>\\n</ul>\\n</li>\\n<li>页面响应上：适当使用防抖和节流，避免重复执行JS逻辑造成页面交互上的阻塞。</li>\\n</ol>"}');export{e as data};
